<?php namespace App\Repositories\Inventory;use App\Repositories\BaseRepository;use App\Models\Inventory\StockMovement;use Illuminate\Database\Eloquent\Collection;class StockMovementRepository extends BaseRepository{    public function __construct(StockMovement $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByItem(int $itemId): Collection    {        return $this->findByField('item_id', $itemId);    }    public function findByType(string $type): Collection    {        return $this->findByField('movement_type', $type);    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('movement_date', [$startDate, $endDate])->get();    }    public function getByReference(string $referenceType, int $referenceId): Collection    {        return $this->query()->where('reference_type', $referenceType)->where('reference_id', $referenceId)->get();    }    public function getRecentMovements(int $limit = 20): Collection    {        return $this->query()->orderBy('created_at', 'desc')->limit($limit)->get();    }    public function getStockInMovements(): Collection    {        return $this->query()->where('movement_type', 'in')->get();    }    public function getStockOutMovements(): Collection    {        return $this->query()->where('movement_type', 'out')->get();    }    public function recordMovement(array $data): StockMovement    {        return $this->create($data);    }    public function getMovementsByItemAndDateRange(int $itemId, string $startDate, string $endDate): Collection    {        return $this->query()->where('item_id', $itemId)->whereBetween('movement_date', [$startDate, $endDate])->orderBy('movement_date', 'asc')->get();    }    public function getTotalStockIn(int $itemId): float    {        return $this->query()->where('item_id', $itemId)->where('movement_type', 'in')->sum('quantity');    }    public function getTotalStockOut(int $itemId): float    {        return $this->query()->where('item_id', $itemId)->where('movement_type', 'out')->sum('quantity');    }}